import{_ as a,c as o,o as i,a2 as t}from"./chunks/framework.CsRv7R0g.js";const m=JSON.parse('{"title":"更新日志","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog.md","filePath":"guide/changelog.md"}'),d={name:"guide/changelog.md"};function l(c,e,r,n,p,h){return i(),o("div",null,e[0]||(e[0]=[t('<h1 id="更新日志" tabindex="-1">更新日志 <a class="header-anchor" href="#更新日志" aria-label="Permalink to &quot;更新日志&quot;">​</a></h1><p>只记录 feat/fix 以及破坏性变更。</p><h2 id="v5-0-0" tabindex="-1">v5.0.0 <a class="header-anchor" href="#v5-0-0" aria-label="Permalink to &quot;v5.0.0&quot;">​</a></h2><p><strong>此版本有较多破坏性的变更，如果打算从 v4.x 升级，请仔细阅读并谨慎迁移代码。</strong></p><ul><li><p>引入 <a href="https://www.shadcn-vue.com/" target="_blank" rel="noreferrer">shadcn-vue</a> ，内建组件和部分扩展组件基于 shadcn-vue 进行重构</p></li><li><p>系统主题重构，挑选了 shadcn-vue 中的 8 款主题并进行定制</p></li><li><p>所有内建组件名均改为 <code>Fa</code> 开头，例如 <code>FaButton</code> 。部分扩展组件也转为内建组件，例如 <code>FaPageHeader</code> 。新增了一系列基于 shadcn-vue 的组件，例如 <code>FaPopover</code> 。为与扩展组件做区分，内建组件存放在 <code>/src/ui/components/</code> 目录下</p></li><li><p>登录页使用内建组件进行重构，不再依赖 <code>element-plus</code> ，更方便迁移其他 UI 组件库</p></li><li><p>新增 <code>app.themeSync</code> 应用设置</p></li><li><p>路由 <code>meta</code> 配置项调整：</p><ul><li>移除 <code>meta.i18n</code> ，<code>meta.title</code> 支持国际化</li><li>移除 <code>meta.sidebar</code> ，改为 <code>meta.menu</code></li><li>移除 <code>meta.paddingBottom</code> ，改为由框架自动处理</li><li>新增 <code>meta.badgeVariant</code> ，用于设置导航徽章颜色</li><li>新增 <code>meta.query</code> ，用于设置点击导航时进行路由跳转时，携带的参数</li><li>新增 <code>meta.maximize</code> ，用于设置访问导航的路由时，是否最大化</li><li>新增 <code>meta.exitMaximize</code> ，用于设置离开导航的路由时，是否退出最大化</li><li>新增 <code>meta.sort</code> ，用于设置导航的排序</li></ul></li><li><p>主导航增加徽章和徽章颜色设置</p></li><li><p>新增 <code>app.loginExpiredMode</code> 应用设置，设置登录状态过期后的行为</p></li><li><p>新增 <code>app.enableCheckUpdates</code> 应用设置，检查网站是否有更新</p></li><li><p>移除 <code>menu.switchMainMenuAndPageJump</code> 应用设置，新增 <code>menu.mainMenuClickMode</code> 应用设置，更灵活控制主导航的点击行为</p></li><li><p>增加全局插槽，用于在导航、顶栏等位置插入自定义内容</p></li></ul><h2 id="v4-x" tabindex="-1">v4.x <a class="header-anchor" href="#v4-x" aria-label="Permalink to &quot;v4.x&quot;">​</a></h2><p>前往 <a href="https://fantastic-admin.hurui.me/v4-docs/guide/changelog.html" target="_blank" rel="noreferrer">v4</a> 文档查看</p><h2 id="v3-x" tabindex="-1">v3.x <a class="header-anchor" href="#v3-x" aria-label="Permalink to &quot;v3.x&quot;">​</a></h2><p>前往 <a href="https://fantastic-admin.hurui.me/v3-docs/guide/changelog.html" target="_blank" rel="noreferrer">v3</a> 文档查看</p><h2 id="v2-x" tabindex="-1">v2.x <a class="header-anchor" href="#v2-x" aria-label="Permalink to &quot;v2.x&quot;">​</a></h2><p>前往 <a href="https://fantastic-admin.hurui.me/v2-docs/guide/changelog.html" target="_blank" rel="noreferrer">v2</a> 文档查看</p>',11)]))}const u=a(d,[["render",l]]);export{m as __pageData,u as default};
